 @page "/inventory"
 @using sv_5b919f10a88d4ffdbd2b62905c679f06.Models
 @using sv_5b919f10a88d4ffdbd2b62905c679f06.Services
 @inject InventoryService InventoryService
 @inject NavigationManager Navigation

 <PageTitle>Inventory</PageTitle>

 <h1>Inventory</h1>

 @* MODE 1 — Static SSR "Quick Add" form *@
 <div class="card mb-4">
     <div class="card-header">Quick Add Product</div>
     <div class="card-body">
         <form method="post" @formname="QuickAddProduct" @onsubmit="HandleAddProduct">
             <AntiforgeryToken />
             <DataAnnotationsValidator />
             <ValidationSummary />

             <div class="row g-2 align-items-end">
                 <div class="col-md-3">
                     <label class="form-label">Name</label>
                     <InputText class="form-control" @bind-Value="NewProduct!.Name" />
                 </div>
                 <div class="col-md-2">
                     <label class="form-label">Quantity</label>
                     <InputNumber class="form-control" @bind-Value="NewProduct!.Quantity" />
                 </div>
                 <div class="col-md-2">
                     <label class="form-label">Unit Price</label>
                     <InputNumber class="form-control" @bind-Value="NewProduct!.UnitPrice" />
                 </div>
                 <div class="col-md-3">
                     <label class="form-label">Category</label>
                     <InputSelect class="form-select" @bind-Value="NewProduct!.Category">
                         <option value="">-- Select --</option>
                         <option value="Electronics">Electronics</option>
                         <option value="Clothing">Clothing</option>
                         <option value="Food">Food</option>
                         <option value="Other">Other</option>
                     </InputSelect>
                 </div>
                 <div class="col-md-2">
                     <button type="submit" class="btn btn-primary w-100">Add</button>
                 </div>
             </div>
         </form>
     </div>
 </div>

 @* Product Table *@
 <table class="table table-striped">
     <thead>
         <tr>
             <th>Name</th>
             <th>Quantity</th>
             <th>Unit Price</th>
             <th>Category</th>
             <th>Actions</th>
         </tr>
     </thead>
     <tbody>
         @if (_products is not null)
         {
             @foreach (var product in _products)
             {
                 @if (_editingProductId == product.Id)
                 {
                     <EditRow Product="product"
                              OnSave="HandleSave"
                              OnCancel="HandleCancel"
                              @rendermode="InteractiveServer" />
                 }
                 else
                 {
                     <tr>
                         <td>@product.Name</td>
                         <td>@product.Quantity</td>
                         <td>@product.UnitPrice.ToString("C")</td>
                         <td>@product.Category</td>
                         <td>
                             <a href="/inventory?edit=@product.Id" class="btn btn-sm btn-outline-secondary">Edit</a>
                         </td>
                     </tr>
                 }
             }
         }
     </tbody>
 </table>

 @code {
     private List<Product>? _products;
     private int? _editingProductId;

     [SupplyParameterFromForm(FormName = "QuickAddProduct")]
     private Product? NewProduct { get; set; }

     [SupplyParameterFromQuery(Name = "edit")]
     private int? EditId { get; set; }

     protected override async Task OnInitializedAsync()
     {
         NewProduct ??= new();
         _products = await InventoryService.GetAllAsync();
         _editingProductId = EditId;
     }

     private async Task HandleAddProduct()
     {
         await InventoryService.AddAsync(NewProduct!);
         Navigation.NavigateTo("/inventory", forceLoad: true);
     }

     private async Task HandleSave(Product product)
     {
         await InventoryService.UpdateAsync(product);
         Navigation.NavigateTo("/inventory", forceLoad: true);
     }

     private void HandleCancel()
     {
         Navigation.NavigateTo("/inventory", forceLoad: true);
     }
 }

